1	<%@ page contentType="text/html;charset=UTF-8" language="java" %>
2	<%@ taglib prefix="c" uri="jakarta.tags.core" %>
3	<!DOCTYPE html>
4	<html lang="en">
5	<head>
6	    <meta charset="UTF-8">
7	    <meta name="viewport" content="width=device-width, initial-scale=1.0">
8	    <title>DispatchOps - Customer Portal</title>
9	    <link rel="stylesheet" href="/static/css/fluent-tokens.css">
10	    <link rel="stylesheet" href="/static/css/app.css">
11	</head>
12	<body>
13	    <div class="login-page">
14	        <div class="card login-card" style="max-width: 520px;">
15	            <div class="login-title">
16	                <h1>DispatchOps</h1>
17	                <p class="text-secondary">Customer Rating &amp; Appeal Portal</p>
18	            </div>
19	
20	            <div class="login-error hidden" id="portal-error"></div>
21	            <div class="hidden" id="portal-success" style="padding:8px;border-radius:4px;background:var(--fluent-color-status-success-bg);color:var(--fluent-color-status-success-fg);margin-bottom:12px;"></div>
22	
23	            <!-- Step 1: Lookup -->
24	            <div id="step-lookup">
25	                <form id="lookup-form">
26	                    <div class="form-group">
27	                        <label class="form-label" for="trackingNumber">Tracking Number</label>
28	                        <input type="text" class="form-input" id="trackingNumber" name="trackingNumber"
29	                               placeholder="e.g. DO-1234567890-5678" required autofocus>
30	                    </div>
31	                    <div class="form-group">
32	                        <label class="form-label" for="customerToken">Customer Token</label>
33	                        <input type="text" class="form-input" id="customerToken" name="customerToken"
34	                               placeholder="Token from your delivery receipt" required>
35	                    </div>
36	                    <button type="submit" class="fluent-btn fluent-btn-primary w-full" id="lookup-btn"
37	                            style="min-height:40px; margin-top: var(--fluent-spacing-s);">
38	                        Look Up Delivery
39	                    </button>
40	                </form>
41	            </div>
42	
43	            <!-- Step 2: Rating / Appeal form (shown after successful lookup) -->
44	            <div id="step-action" class="hidden">
45	                <div style="margin-bottom:16px;">
46	                    <strong>Delivery:</strong> <span id="info-tracking"></span><br>
47	                    <strong>Receiver:</strong> <span id="info-receiver"></span><br>
48	                    <strong>Status:</strong> <span id="info-status"></span>
49	                </div>
50	
51	                <div id="rating-section">
52	                    <h3 style="margin-bottom:8px;">Rate this Delivery</h3>
53	                    <form id="rating-form">
54	                        <div class="form-group">
55	                            <label class="form-label">Timeliness (1-5)</label>
56	                            <input type="number" class="form-input" id="timeliness" min="1" max="5" required>
57	                        </div>
58	                        <div class="form-group">
59	                            <label class="form-label">Attitude (1-5)</label>
60	                            <input type="number" class="form-input" id="attitude" min="1" max="5" required>
61	                        </div>
62	                        <div class="form-group">
63	                            <label class="form-label">Accuracy (1-5)</label>
64	                            <input type="number" class="form-input" id="accuracy" min="1" max="5" required>
65	                        </div>
66	                        <div class="form-group">
67	                            <label class="form-label">Comment (optional)</label>
68	                            <textarea class="form-input" id="comment" rows="3"></textarea>
69	                        </div>
70	                        <button type="submit" class="fluent-btn fluent-btn-primary w-full" id="rate-btn"
71	                                style="min-height:40px;">Submit Rating</button>
72	                    </form>
73	                </div>
74	
75	                <div style="margin-top:16px;">
76	                    <button class="fluent-btn fluent-btn-secondary w-full" id="back-btn"
77	                            style="min-height:36px;">Back to Lookup</button>
78	                </div>
79	            </div>
80	        </div>
81	    </div>
82	
83	    <div class="toast-container" id="toast-container"></div>
84	
85	    <script src="/static/js/vendor/jquery-3.7.1.min.js"></script>
86	    <script src="/static/js/common/util.js"></script>
87	    <script src="/static/js/common/toast.js"></script>
88	    <script>
89	    $(function() {
90	        var currentTracking, currentToken, currentReceiver;
91	
92	        $('#lookup-form').on('submit', function(e) {
93	            e.preventDefault();
94	            $('#portal-error').addClass('hidden');
95	            currentTracking = $('#trackingNumber').val().trim();
96	            currentToken = $('#customerToken').val().trim();
97	
98	            $('#lookup-btn').prop('disabled', true).text('Looking up...');
99	
100	            $.ajax({
101	                url: '/api/credibility/customer/lookup',
102	                method: 'GET',
103	                data: { trackingNumber: currentTracking, customerToken: currentToken }
104	            }).done(function(resp) {
105	                if (resp.code === 200 && resp.data) {
106	                    currentReceiver = resp.data.receiverName;
107	                    $('#info-tracking').text(resp.data.trackingNumber);
108	                    $('#info-receiver').text(resp.data.receiverName);
109	                    $('#info-status').text(resp.data.status);
110	                    $('#step-lookup').addClass('hidden');
111	                    $('#step-action').removeClass('hidden');
112	                    if (!resp.data.canRate) {
113	                        $('#rating-section').html('<p class="text-secondary">This delivery is not yet eligible for rating.</p>');
114	                    }
115	                } else {
116	                    $('#portal-error').text(resp.message || 'Lookup failed.').removeClass('hidden');
117	                }
118	                $('#lookup-btn').prop('disabled', false).text('Look Up Delivery');
119	            }).fail(function(xhr) {
120	                var msg = xhr.responseJSON && xhr.responseJSON.message ? xhr.responseJSON.message : 'Unable to find delivery.';
121	                $('#portal-error').text(msg).removeClass('hidden');
122	                $('#lookup-btn').prop('disabled', false).text('Look Up Delivery');
123	            });
124	        });
125	
126	        $('#rating-form').on('submit', function(e) {
127	            e.preventDefault();
128	            $('#portal-error').addClass('hidden');
129	            $('#rate-btn').prop('disabled', true).text('Submitting...');
130	
131	            $.ajax({
132	                url: '/api/credibility/ratings/customer',
133	                method: 'POST',
134	                contentType: 'application/json',
135	                data: JSON.stringify({
136	                    trackingNumber: currentTracking,
137	                    receiverName: currentReceiver,
138	                    customerToken: currentToken,
139	                    timeliness: parseInt($('#timeliness').val()),
140	                    attitude: parseInt($('#attitude').val()),
141	                    accuracy: parseInt($('#accuracy').val()),
142	                    comment: $('#comment').val()
143	                })
144	            }).done(function(resp) {
145	                if (resp.code === 200 || resp.code === 201) {
146	                    $('#portal-success').text('Thank you! Your rating has been submitted.').removeClass('hidden');
147	                    $('#rating-section').addClass('hidden');
148	                } else {
149	                    $('#portal-error').text(resp.message || 'Rating submission failed.').removeClass('hidden');
150	                }
151	                $('#rate-btn').prop('disabled', false).text('Submit Rating');
152	            }).fail(function(xhr) {
153	                var msg = xhr.responseJSON && xhr.responseJSON.message ? xhr.responseJSON.message : 'Rating submission failed.';
154	                $('#portal-error').text(msg).removeClass('hidden');
155	                $('#rate-btn').prop('disabled', false).text('Submit Rating');
156	            });
157	        });
158	
159	        $('#back-btn').on('click', function() {
160	            $('#step-action').addClass('hidden');
161	            $('#step-lookup').removeClass('hidden');
162	            $('#portal-error').addClass('hidden');
163	            $('#portal-success').addClass('hidden');
164	        });
165	    });
166	    </script>
167	</body>
168	</html>
