25	@RestController
26	@RequestMapping("/api/credibility")
27	public class CredibilityController {
28	
29	    private static final Logger log = LoggerFactory.getLogger(CredibilityController.class);
30	
31	    private final CredibilityService credibilityService;
32	
33	    public CredibilityController(CredibilityService credibilityService) {
34	        this.credibilityService = credibilityService;
35	    }
36	
37	    @PostMapping("/ratings")
38	    @RequireRole({Role.DISPATCHER, Role.OPS_MANAGER, Role.ADMIN, Role.AUDITOR})
39	    public ResponseEntity<ApiResult<CredibilityRating>> submitRating(
40	            @Valid @RequestBody RatingSubmitDTO dto,
41	            HttpSession session) {
42	        User currentUser = (User) session.getAttribute("currentUser");
43	        log.info("User '{}' submitting rating for job {}", currentUser.getUsername(), dto.getJobId());
44	        CredibilityRating rating = credibilityService.submitRating(
45	                dto.getJobId(), dto.getTimeliness(), dto.getAttitude(), dto.getAccuracy(),
46	                dto.getComment(), currentUser.getId());
47	        return ResponseEntity.status(201).body(ApiResult.success(rating));
48	    }
49	
50	    /**
51	     * Customer rating endpoint - allows external customers to rate via tracking number.
52	     * Per prompt: "Customers and Dispatchers rate completed deliveries."
53	     * This endpoint does not require session auth; validated by tracking number + receiver name.
54	     */
55	    /** Time-windowed rate limiter with TTL eviction and capped cardinality. Max 10 per hour per IP. */
56	    private final java.util.concurrent.ConcurrentHashMap<String, java.util.concurrent.CopyOnWriteArrayList<Long>> customerRateLimits = new java.util.concurrent.ConcurrentHashMap<>();
57	    private static final int RATE_LIMIT_MAX = 10;
58	    private static final long RATE_LIMIT_WINDOW_MS = 3600_000L; // 1 hour
59	    private static final int RATE_LIMIT_MAX_KEYS = 10_000; // cap map cardinality
60	    private volatile long lastEvictionMs = System.currentTimeMillis();
61	
62	    private boolean isRateLimited(String ip) {
63	        long now = System.currentTimeMillis();
64	        long cutoff = now - RATE_LIMIT_WINDOW_MS;
65	
66	        // Periodic global eviction: remove stale IPs every 5 minutes
67	        if (now - lastEvictionMs > 300_000L) {
68	            lastEvictionMs = now;
69	            customerRateLimits.entrySet().removeIf(entry -> {
70	                entry.getValue().removeIf(t -> t < cutoff);
71	                return entry.getValue().isEmpty();
72	            });
73	        }
74	
75	        // Hard cardinality cap: reject if map is full and IP is new
76	        if (!customerRateLimits.containsKey(ip) && customerRateLimits.size() >= RATE_LIMIT_MAX_KEYS) {
77	            log.warn("Rate limiter cardinality cap reached ({}), rejecting new IP={}", RATE_LIMIT_MAX_KEYS, ip);
78	            return true;
79	        }
80	
81	        var timestamps = customerRateLimits.computeIfAbsent(ip, k -> new java.util.concurrent.CopyOnWriteArrayList<>());
82	        // Prune expired entries for this IP
83	        timestamps.removeIf(t -> t < cutoff);
84	        if (timestamps.size() >= RATE_LIMIT_MAX) {
85	            return true;
86	        }
87	        timestamps.add(now);
88	        return false;
89	    }
90	
91	    @PostMapping("/ratings/customer")
92	    public ResponseEntity<ApiResult<CredibilityRating>> submitCustomerRating(
93	            @Valid @RequestBody com.dispatchops.web.dto.CustomerRatingDTO dto,
94	            jakarta.servlet.http.HttpServletRequest request) {
95	        String ip = request.getRemoteAddr();
96	        if (isRateLimited(ip)) {
97	            log.warn("Customer rate limit exceeded for IP={}, tracking={}", ip, dto.getTrackingNumber());
98	            return ResponseEntity.status(429).body(ApiResult.error(429, "Too many requests. Please try again later."));
99	        }
100	        log.info("Customer rating submission for tracking={} from IP={}", dto.getTrackingNumber(), ip);
101	        try {
102	            CredibilityRating rating = credibilityService.submitCustomerRating(
103	                    dto.getTrackingNumber(), dto.getReceiverName(), dto.getCustomerToken(),
104	                    dto.getTimeliness(), dto.getAttitude(), dto.getAccuracy(), dto.getComment());
105	            return ResponseEntity.status(201).body(ApiResult.success(rating));
106	        } catch (com.dispatchops.domain.exception.ResourceNotFoundException | com.dispatchops.domain.exception.PermissionDeniedException e) {
107	            // Normalize to prevent enumeration: don't distinguish not-found from permission-denied
108	            return ResponseEntity.status(422).body(ApiResult.error(422, "Unable to process rating. Verify tracking number and receiver name."));
109	        }
110	    }
111	
112	    @GetMapping("/customer/lookup")
113	    public ResponseEntity<ApiResult<Map<String, Object>>> customerLookup(
114	            @RequestParam String trackingNumber,
115	            @RequestParam String customerToken) {
116	        log.debug("Customer lookup for tracking={}", trackingNumber);
117	        try {
118	            Map<String, Object> info = credibilityService.lookupCustomerJob(trackingNumber, customerToken);
119	            return ResponseEntity.ok(ApiResult.success(info));
120	        } catch (com.dispatchops.domain.exception.ResourceNotFoundException | com.dispatchops.domain.exception.PermissionDeniedException e) {
121	            return ResponseEntity.status(422).body(ApiResult.error(422, "Unable to find delivery. Verify tracking number and token."));
122	        }
123	    }
124	
125	    @GetMapping("/ratings/courier/{id}")
126	    @RequireRole({Role.OPS_MANAGER, Role.ADMIN, Role.AUDITOR})
127	    public ResponseEntity<ApiResult<PageResult<CredibilityRating>>> listRatings(
128	            @PathVariable Long id,
129	            @RequestParam(defaultValue = "0") int page,
130	            @RequestParam(defaultValue = "25") int size) {
131	        log.debug("Listing ratings for courier {} - page: {}, size: {}", id, page, size);
132	        PageResult<CredibilityRating> result = credibilityService.listRatings(id, page, size);
133	        return ResponseEntity.ok(ApiResult.success(result));
134	    }
135	
136	    @GetMapping("/credit/{courierId}")
137	    public ResponseEntity<ApiResult<CreditLevelSnapshot>> getCreditLevel(
138	            @PathVariable Long courierId, HttpSession session) {
139	        User currentUser = (User) session.getAttribute("currentUser");
140	        // Object-level auth: COURIER can only view own credit level
141	        if (currentUser.getRole() == Role.COURIER && !currentUser.getId().equals(courierId)) {
142	            throw new com.dispatchops.domain.exception.PermissionDeniedException(
143	                    "Courier can only view their own credit level");
144	        }
145	        log.debug("Getting credit level for courier {}", courierId);
146	        CreditLevelSnapshot snapshot = credibilityService.getCourierCredibility(courierId);
147	        return ResponseEntity.ok(ApiResult.success(snapshot));
148	    }
149	
150	    @PostMapping("/violations")
151	    @RequireRole({Role.OPS_MANAGER, Role.ADMIN})
152	    public ResponseEntity<ApiResult<Violation>> recordViolation(
153	            @RequestBody Violation violation,
154	            HttpSession session) {
155	        User currentUser = (User) session.getAttribute("currentUser");
156	        log.info("User '{}' recording violation for courier {}", currentUser.getUsername(), violation.getCourierId());
157	        Violation result = credibilityService.recordViolation(
158	                violation.getCourierId(), violation.getViolationType(), violation.getDescription(),
159	                violation.getJobId(), currentUser.getId());
160	        return ResponseEntity.status(201).body(ApiResult.success(result));
161	    }
162	
163	    @GetMapping("/violations/courier/{id}")
164	    @RequireRole({Role.OPS_MANAGER, Role.ADMIN, Role.AUDITOR, Role.COURIER})
165	    public ResponseEntity<ApiResult<List<Violation>>> listViolations(
166	            @PathVariable Long id,
167	            HttpSession session) {
168	        User currentUser = (User) session.getAttribute("currentUser");
169	
170	        // COURIER can only view their own violations
171	        if (currentUser.getRole() == Role.COURIER && !currentUser.getId().equals(id)) {
172	            return ResponseEntity.status(403)
173	                    .body(ApiResult.error(403, "Couriers can only view their own violations"));
174	        }
175	
176	        log.debug("Listing violations for courier {}", id);
177	        List<Violation> result = credibilityService.listViolations(id);
178	        return ResponseEntity.ok(ApiResult.success(result));
179	    }
180	
181	    @PostMapping("/appeals")
182	    @RequireRole({Role.COURIER})
183	    public ResponseEntity<ApiResult<Appeal>> fileAppeal(
184	            @Valid @RequestBody AppealCreateDTO dto,
185	            HttpSession session) {
186	        User currentUser = (User) session.getAttribute("currentUser");
187	        log.info("Courier '{}' filing appeal", currentUser.getUsername());
188	        Appeal appeal = credibilityService.fileAppeal(
189	                dto.getRatingId(), dto.getViolationId(), dto.getReason(), currentUser.getId());
190	        return ResponseEntity.status(201).body(ApiResult.success(appeal));
191	    }
192	
193	    /**
194	     * Customer appeal endpoint - allows customers to appeal ratings via tracking number.
195	     * Per prompt: "Customers...may file an appeal within 48 hours."
196	     */
197	    @PostMapping("/appeals/customer")
198	    public ResponseEntity<ApiResult<Appeal>> fileCustomerAppeal(
199	            @Valid @RequestBody com.dispatchops.web.dto.CustomerAppealDTO dto,
200	            jakarta.servlet.http.HttpServletRequest request) {
201	        String ip = request.getRemoteAddr();
202	        if (isRateLimited(ip)) {
203	            log.warn("Customer rate limit exceeded for IP={}, tracking={}", ip, dto.getTrackingNumber());
204	            return ResponseEntity.status(429).body(ApiResult.error(429, "Too many requests. Please try again later."));
205	        }
206	        log.info("Customer appeal for tracking={} from IP={}", dto.getTrackingNumber(), ip);
207	        try {
208	            Appeal appeal = credibilityService.fileCustomerAppeal(
209	                    dto.getTrackingNumber(), dto.getReceiverName(), dto.getCustomerToken(),
210	                    dto.getRatingId(), dto.getReason());
211	            return ResponseEntity.status(201).body(ApiResult.success(appeal));
212	        } catch (com.dispatchops.domain.exception.ResourceNotFoundException | com.dispatchops.domain.exception.PermissionDeniedException e) {
213	            return ResponseEntity.status(422).body(ApiResult.error(422, "Unable to process appeal. Verify tracking number and receiver name."));
214	        }
215	    }
216	
217	    @GetMapping("/appeals")
218	    @RequireRole({Role.OPS_MANAGER, Role.ADMIN})
219	    public ResponseEntity<ApiResult<PageResult<Appeal>>> listPendingAppeals(
220	            @RequestParam(defaultValue = "0") int page,
221	            @RequestParam(defaultValue = "25") int size) {
222	        log.debug("Listing pending appeals - page: {}, size: {}", page, size);
223	        PageResult<Appeal> result = credibilityService.listPendingAppeals(page, size);
224	        return ResponseEntity.ok(ApiResult.success(result));
225	    }
226	
227	    @PutMapping("/appeals/{id}/resolve")
228	    @RequireRole({Role.OPS_MANAGER, Role.ADMIN})
229	    public ResponseEntity<ApiResult<Appeal>> resolveAppeal(
230	            @PathVariable Long id,
231	            @Valid @RequestBody com.dispatchops.web.dto.AppealResolveDTO dto,
232	            HttpSession session) {
233	        User currentUser = (User) session.getAttribute("currentUser");
234	        String status = dto.getStatus();
235	        String comment = dto.getComment();
236	        log.info("User '{}' resolving appeal {} with status '{}'", currentUser.getUsername(), id, status);
237	        Appeal appeal = credibilityService.resolveAppeal(id, status, comment, currentUser.getId());
238	        return ResponseEntity.ok(ApiResult.success(appeal));
239	    }
240	}
