1	package com.dispatchops.e2e;
2	
3	import com.microsoft.playwright.*;
4	import org.junit.jupiter.api.*;
5	
6	/**
7	 * E2E tests for customer-facing credibility endpoints (no session required).
8	 * All assertions are strict single-status where deterministic.
9	 */
10	class CustomerCredibilityFlowTest extends BaseE2ETest {
11	
12	    @Test
13	    void customerRatingOnNonExistentTrackingReturns404() {
14	        APIResponse resp = page.request().post(BASE_URL + "/api/credibility/ratings/customer",
15	                com.microsoft.playwright.options.RequestOptions.create()
16	                        .setHeader("Content-Type", "application/json")
17	                        .setData("{\"trackingNumber\":\"DO-NONEXISTENT\",\"receiverName\":\"John\"," +
18	                                "\"timeliness\":5,\"attitude\":4,\"accuracy\":5,\"comment\":\"Great\"}"));
19	        Assertions.assertEquals(404, resp.status(), "Non-existent tracking should return 404");
20	    }
21	
22	    @Test
23	    void customerRatingMissingFieldsReturns422() {
24	        APIResponse resp = page.request().post(BASE_URL + "/api/credibility/ratings/customer",
25	                com.microsoft.playwright.options.RequestOptions.create()
26	                        .setHeader("Content-Type", "application/json")
27	                        .setData("{\"trackingNumber\":\"X\"}"));
28	        Assertions.assertEquals(422, resp.status(), "Missing fields should return 422");
29	    }
30	
31	    @Test
32	    void customerAppealOnNonExistentTrackingReturns404() {
33	        APIResponse resp = page.request().post(BASE_URL + "/api/credibility/appeals/customer",
34	                com.microsoft.playwright.options.RequestOptions.create()
35	                        .setHeader("Content-Type", "application/json")
36	                        .setData("{\"trackingNumber\":\"DO-NONEXISTENT\",\"receiverName\":\"John\"," +
37	                                "\"reason\":\"I want to appeal this rating.\"}"));
38	        Assertions.assertEquals(404, resp.status(), "Non-existent tracking should return 404");
39	    }
40	
41	    @Test
42	    void customerAppealMissingFieldsReturns422() {
43	        APIResponse resp = page.request().post(BASE_URL + "/api/credibility/appeals/customer",
44	                com.microsoft.playwright.options.RequestOptions.create()
45	                        .setHeader("Content-Type", "application/json")
46	                        .setData("{\"trackingNumber\":\"X\"}"));
47	        Assertions.assertEquals(422, resp.status(), "Missing fields should return 422");
48	    }
49	
50	    @Test
51	    void customerEndpointsDoNotReturn401() {
52	        APIResponse ratingResp = page.request().post(BASE_URL + "/api/credibility/ratings/customer",
53	                com.microsoft.playwright.options.RequestOptions.create()
54	                        .setHeader("Content-Type", "application/json")
55	                        .setData("{\"trackingNumber\":\"X\",\"receiverName\":\"Y\"," +
56	                                "\"timeliness\":3,\"attitude\":3,\"accuracy\":3}"));
57	        Assertions.assertNotEquals(401, ratingResp.status(), "Must not require session");
58	
59	        APIResponse appealResp = page.request().post(BASE_URL + "/api/credibility/appeals/customer",
60	                com.microsoft.playwright.options.RequestOptions.create()
61	                        .setHeader("Content-Type", "application/json")
62	                        .setData("{\"trackingNumber\":\"X\",\"receiverName\":\"Y\",\"reason\":\"test\"}"));
63	        Assertions.assertNotEquals(401, appealResp.status(), "Must not require session");
64	    }
65	}
