1	package com.dispatchops.web.controller;
2	
3	import com.dispatchops.application.service.TaskService;
4	import com.dispatchops.domain.exception.PermissionDeniedException;
5	import com.dispatchops.domain.model.InternalTask;
6	import com.dispatchops.domain.model.TaskComment;
7	import com.dispatchops.domain.model.User;
8	import com.dispatchops.domain.model.enums.Role;
9	import com.dispatchops.web.annotation.RequireRole;
10	import com.dispatchops.web.dto.ApiResult;
11	import com.dispatchops.web.dto.PageResult;
12	import com.dispatchops.web.dto.StatusTransitionDTO;
13	import com.dispatchops.web.dto.TaskCreateDTO;
14	import jakarta.servlet.http.HttpSession;
15	import jakarta.validation.Valid;
16	import org.slf4j.Logger;
17	import org.slf4j.LoggerFactory;
18	import org.springframework.http.ResponseEntity;
19	import org.springframework.web.bind.annotation.*;
20	
21	import java.time.LocalDate;
22	import java.util.List;
23	import java.util.Map;
24	import java.util.stream.Collectors;
25	
26	@RestController
27	@RequestMapping("/api/tasks")
28	public class TaskController {
29	
