84	    public CredibilityRating submitRating(Long jobId, int timeliness, int attitude, int accuracy,
85	                                           String comment, Long raterId) {
86	        log.info("Submitting rating for jobId={} by raterId={}", jobId, raterId);
87	
88	        DeliveryJob job = deliveryJobMapper.findById(jobId);
89	        if (job == null) {
90	            throw new ResourceNotFoundException("Delivery job not found with id: " + jobId, "DeliveryJob", jobId);
91	        }
92	
93	        if (job.getStatus() != JobStatus.DELIVERED) {
94	            throw new IllegalStateException(
95	                    "Cannot rate a job that is not in DELIVERED status. Current status: " + job.getStatus());
96	        }
97	
98	        CredibilityRating rating = new CredibilityRating();
99	        rating.setCourierId(job.getCourierId());
100	        rating.setJobId(jobId);
101	        rating.setRaterId(raterId);
102	        rating.setRaterType("STAFF");
103	        rating.setTimeliness(timeliness);
104	        rating.setAttitude(attitude);
105	        rating.setAccuracy(accuracy);
