133	    /**
134	     * Validates the customer action token against the stored token on the job.
135	     * Recomputes the expected token from job data + HMAC key and compares using timing-safe equality.
136	     */
137	    private void validateCustomerToken(DeliveryJob job, String customerToken) {
138	        if (job.getCustomerToken() == null) {
139	            throw new com.dispatchops.domain.exception.PermissionDeniedException(
140	                    "Customer action token not available for this job");
141	        }
142	        String expected = HmacUtil.computeHmac(
143	                job.getTrackingNumber() + "|" + job.getReceiverName() + "|" + job.getId(),
144	                hmacKey).substring(0, 32);
145	        if (!java.security.MessageDigest.isEqual(
146	                expected.getBytes(java.nio.charset.StandardCharsets.UTF_8),
147	                customerToken.getBytes(java.nio.charset.StandardCharsets.UTF_8))) {
148	            throw new com.dispatchops.domain.exception.PermissionDeniedException(
149	                    "Invalid customer action token");
150	        }
151	    }
