162	        DeliveryJob job = deliveryJobMapper.findByTrackingNumber(trackingNumber);
163	        if (job == null) {
164	            throw new ResourceNotFoundException("Delivery job not found with tracking: " + trackingNumber, "DeliveryJob", trackingNumber);
165	        }
