167	        if (job.getStatus() != com.dispatchops.domain.model.enums.JobStatus.DELIVERED) {
168	            throw new IllegalStateException("Cannot rate a job that is not DELIVERED. Current: " + job.getStatus());
169	        }
170	
171	        // Validate receiver name matches - use generic error to prevent enumeration
172	        if (!job.getReceiverName().equalsIgnoreCase(receiverName)) {
173	            throw new com.dispatchops.domain.exception.PermissionDeniedException(
174	                    "Invalid tracking number or receiver name");
175	        }
176	
177	        // Validate customer action token
178	        validateCustomerToken(job, customerToken);
179	
180	        // Customer ratings: rater_id is NULL (no user account), rater_type=CUSTOMER.
181	        // customer_name provides the attribution identity. Unique per (job_id, customer_name).
182	        CredibilityRating rating = new CredibilityRating();
183	        rating.setCourierId(job.getCourierId());
184	        rating.setJobId(job.getId());
185	        rating.setRaterId(null);
186	        rating.setRaterType("CUSTOMER");
187	        rating.setTimeliness(timeliness);
188	        rating.setAttitude(attitude);
189	        rating.setAccuracy(accuracy);
190	        rating.setComment(comment);
191	        rating.setCustomerName(receiverName);
192	        rating.setExcluded(false);
193	        rating.setCreatedAt(LocalDateTime.now());
194	
195	        try {
196	            credibilityRatingMapper.insert(rating);
197	        } catch (org.springframework.dao.DuplicateKeyException e) {
198	            throw new com.dispatchops.domain.exception.IdempotencyViolationException(
199	                    "A customer rating for this job has already been submitted", job.getId());
200	        }
201	        log.info("Customer rating id={} created for job {} by customer '{}'", rating.getId(), job.getId(), receiverName);
202	
203	        if (job.getCourierId() != null) {
204	            recalculateCreditLevel(job.getCourierId());
205	        }
206	        return rating;
207	    }
