212	     */
213	    public Appeal fileCustomerAppeal(String trackingNumber, String receiverName, String customerToken,
214	                                      Long ratingId, String reason) {
215	        log.info("Customer appeal for trackingNumber={}", trackingNumber);
216	
217	        DeliveryJob job = deliveryJobMapper.findByTrackingNumber(trackingNumber);
218	        if (job == null) {
219	            throw new ResourceNotFoundException("Job not found: " + trackingNumber, "DeliveryJob", trackingNumber);
220	        }
221	        if (!job.getReceiverName().equalsIgnoreCase(receiverName)) {
222	            throw new com.dispatchops.domain.exception.PermissionDeniedException("Invalid tracking number or receiver name");
223	        }
224	
225	        // Validate customer action token
226	        validateCustomerToken(job, customerToken);
227	
228	        // Validate rating belongs to the resolved job (prevents cross-object targeting)
229	        Long courierId = null;
230	        if (ratingId != null) {
231	            CredibilityRating rating = credibilityRatingMapper.findById(ratingId);
232	            if (rating == null) {
233	                throw new ResourceNotFoundException("Rating not found: " + ratingId, "CredibilityRating", ratingId);
234	            }
235	            if (!rating.getJobId().equals(job.getId())) {
236	                throw new com.dispatchops.domain.exception.PermissionDeniedException(
237	                        "Rating " + ratingId + " does not belong to job " + job.getTrackingNumber());
238	            }
239	            courierId = rating.getCourierId();
240	        }
241	        if (courierId == null) {
242	            courierId = job.getCourierId();
243	        }
244	
245	        String auditReason = "[Customer: " + receiverName + "] " + reason;
246	        return fileAppeal(ratingId, null, auditReason, courierId);
247	    }
