249	    public Appeal fileAppeal(Long ratingId, Long violationId, String reason, Long courierId) {
250	        log.info("Filing appeal by courierId={}, ratingId={}, violationId={}", courierId, ratingId, violationId);
251	
252	        // Exactly one of ratingId or violationId must be provided
253	        if (ratingId == null && violationId == null) {
254	            throw new IllegalArgumentException("Appeal must reference either a ratingId or a violationId");
255	        }
256	        if (ratingId != null && violationId != null) {
257	            throw new IllegalArgumentException("Appeal must reference exactly one of ratingId or violationId, not both");
258	        }
259	
260	        LocalDateTime now = LocalDateTime.now();
261	
262	        if (ratingId != null) {
263	            CredibilityRating rating = credibilityRatingMapper.findById(ratingId);
264	            if (rating == null) {
265	                throw new ResourceNotFoundException("Rating not found with id: " + ratingId, "CredibilityRating", ratingId);
266	            }
267	            // Ownership check: rating must be about this courier
268	            if (!rating.getCourierId().equals(courierId)) {
269	                throw new com.dispatchops.domain.exception.PermissionDeniedException(
270	                        "Rating " + ratingId + " does not belong to courier " + courierId);
271	            }
272	            if (rating.getCreatedAt().plusHours(APPEAL_WINDOW_HOURS).isBefore(now)) {
273	                throw new AppealWindowClosedException(
274	                        "Appeal window has closed. Ratings must be appealed within " + APPEAL_WINDOW_HOURS + " hours.");
275	            }
276	        }
277	
278	        if (violationId != null) {
279	            Violation violation = violationMapper.findById(violationId);
280	            if (violation == null) {
281	                throw new ResourceNotFoundException("Violation not found with id: " + violationId, "Violation", violationId);
282	            }
283	            // Ownership check: violation must be about this courier
284	            if (!violation.getCourierId().equals(courierId)) {
285	                throw new com.dispatchops.domain.exception.PermissionDeniedException(
286	                        "Violation " + violationId + " does not belong to courier " + courierId);
287	            }
288	            if (violation.getCreatedAt().plusHours(APPEAL_WINDOW_HOURS).isBefore(now)) {
289	                throw new AppealWindowClosedException(
290	                        "Appeal window has closed. Violations must be appealed within " + APPEAL_WINDOW_HOURS + " hours.");
291	            }
292	        }
293	
294	        Appeal appeal = new Appeal();
295	        appeal.setRatingId(ratingId);
296	        appeal.setViolationId(violationId);
297	        appeal.setCourierId(courierId);
298	        appeal.setReason(reason);
299	        appeal.setStatus(AppealStatus.PENDING);
300	        appeal.setCreatedAt(LocalDateTime.now());
301	
302	        appealMapper.insert(appeal);
303	        log.info("Appeal id={} filed by courier {}", appeal.getId(), courierId);
304	
305	        List<com.dispatchops.domain.model.User> admins = userMapper.findByRole(Role.ADMIN.name());
306	        for (com.dispatchops.domain.model.User admin : admins) {
307	            notificationService.notify(
308	                    admin.getId(),
309	                    NotificationType.APPEAL_UPDATE,
310	                    "New Appeal Filed",
311	                    "Courier has filed an appeal requiring review",
312	                    "Appeal",
313	                    appeal.getId());
314	        }
315	
316	        return appeal;
317	    }
