319	    public Appeal resolveAppeal(Long appealId, String statusStr, String comment, Long reviewerId) {
320	        log.info("Resolving appeal id={} with status={} by reviewerId={}", appealId, statusStr, reviewerId);
321	
322	        Appeal appeal = appealMapper.findById(appealId);
323	        if (appeal == null) {
324	            throw new ResourceNotFoundException("Appeal not found with id: " + appealId, "Appeal", appealId);
325	        }
326	
327	        AppealStatus status = AppealStatus.valueOf(statusStr);
328	        LocalDateTime now = LocalDateTime.now();
329	
330	        int rowsUpdated = appealMapper.resolve(appealId, statusStr, reviewerId, comment, now);
331	        if (rowsUpdated == 0) {
332	            throw new IllegalStateException("Appeal " + appealId + " is no longer in PENDING status (already resolved)");
333	        }
334	
335	        if (status == AppealStatus.APPROVED) {
336	            if (appeal.getRatingId() != null) {
337	                credibilityRatingMapper.excludeRating(appeal.getRatingId());
338	                log.info("Rating id={} excluded due to approved appeal", appeal.getRatingId());
339	            }
340	            if (appeal.getViolationId() != null) {
341	                violationMapper.deactivate(appeal.getViolationId());
342	                log.info("Violation id={} deactivated due to approved appeal", appeal.getViolationId());
343	            }
344	        }
345	
346	        recalculateCreditLevel(appeal.getCourierId());
347	
348	        notificationService.notify(
349	                appeal.getCourierId(),
350	                NotificationType.APPEAL_UPDATE,
351	                "Appeal " + status.name(),
352	                "Your appeal has been " + status.name().toLowerCase() + "." +
353	                        (comment != null ? " Reviewer comment: " + comment : ""),
354	                "Appeal",
355	                appealId);
356	
357	        appeal.setStatus(status);
358	        appeal.setReviewerId(reviewerId);
359	        appeal.setReviewerComment(comment);
360	        appeal.setResolvedAt(now);
361	
362	        log.info("Appeal {} resolved with status {}", appealId, status);
363	        return appeal;
364	    }
