399	    public CreditLevelSnapshot recalculateCreditLevel(Long courierId) {
400	        log.info("Recalculating credit level for courierId={}", courierId);
401	
402	        BigDecimal avgRating30d = credibilityRatingMapper.calculateAvgRating30d(courierId);
403	        int activeViolations = violationMapper.countActiveByCourierId(courierId);
404	
405	        CreditLevel level = CreditLevelCalculator.calculate(avgRating30d, activeViolations);
