50	    /**
51	     * Customer rating endpoint - allows external customers to rate via tracking number.
52	     * Per prompt: "Customers and Dispatchers rate completed deliveries."
53	     * This endpoint does not require session auth; validated by tracking number + receiver name.
54	     */
55	    /** Time-windowed rate limiter with TTL eviction and capped cardinality. Max 10 per hour per IP. */
56	    private final java.util.concurrent.ConcurrentHashMap<String, java.util.concurrent.CopyOnWriteArrayList<Long>> customerRateLimits = new java.util.concurrent.ConcurrentHashMap<>();
57	    private static final int RATE_LIMIT_MAX = 10;
58	    private static final long RATE_LIMIT_WINDOW_MS = 3600_000L; // 1 hour
59	    private static final int RATE_LIMIT_MAX_KEYS = 10_000; // cap map cardinality
60	    private volatile long lastEvictionMs = System.currentTimeMillis();
61	
62	    private boolean isRateLimited(String ip) {
63	        long now = System.currentTimeMillis();
64	        long cutoff = now - RATE_LIMIT_WINDOW_MS;
65	
66	        // Periodic global eviction: remove stale IPs every 5 minutes
67	        if (now - lastEvictionMs > 300_000L) {
68	            lastEvictionMs = now;
69	            customerRateLimits.entrySet().removeIf(entry -> {
70	                entry.getValue().removeIf(t -> t < cutoff);
71	                return entry.getValue().isEmpty();
72	            });
73	        }
74	
75	        // Hard cardinality cap: reject if map is full and IP is new
76	        if (!customerRateLimits.containsKey(ip) && customerRateLimits.size() >= RATE_LIMIT_MAX_KEYS) {
77	            log.warn("Rate limiter cardinality cap reached ({}), rejecting new IP={}", RATE_LIMIT_MAX_KEYS, ip);
78	            return true;
79	        }
80	
81	        var timestamps = customerRateLimits.computeIfAbsent(ip, k -> new java.util.concurrent.CopyOnWriteArrayList<>());
82	        // Prune expired entries for this IP
83	        timestamps.removeIf(t -> t < cutoff);
84	        if (timestamps.size() >= RATE_LIMIT_MAX) {
85	            return true;
86	        }
87	        timestamps.add(now);
88	        return false;
89	    }
