1	<%@ page contentType="text/html;charset=UTF-8" language="java" %>
2	<%@ taglib prefix="c" uri="jakarta.tags.core" %>
3	<!DOCTYPE html>
4	<html lang="en">
5	<head>
6	    <meta charset="UTF-8">
7	    <meta name="viewport" content="width=device-width, initial-scale=1.0">
8	    <title>DispatchOps - Customer Portal</title>
9	    <link rel="stylesheet" href="/static/css/fluent-tokens.css">
10	    <link rel="stylesheet" href="/static/css/app.css">
11	</head>
12	<body>
13	    <div class="login-page">
14	        <div class="card login-card" style="max-width: 520px;">
15	            <div class="login-title">
16	                <h1>DispatchOps</h1>
17	                <p class="text-secondary">Customer Rating &amp; Appeal Portal</p>
18	            </div>
19	
20	            <div class="login-error hidden" id="portal-error"></div>
21	            <div class="hidden" id="portal-success" style="padding:8px;border-radius:4px;background:var(--fluent-color-status-success-bg);color:var(--fluent-color-status-success-fg);margin-bottom:12px;"></div>
22	
23	            <!-- Step 1: Lookup -->
24	            <div id="step-lookup">
25	                <form id="lookup-form">
26	                    <div class="form-group">
27	                        <label class="form-label" for="trackingNumber">Tracking Number</label>
28	                        <input type="text" class="form-input" id="trackingNumber" name="trackingNumber"
29	                               placeholder="e.g. DO-1234567890-5678" required autofocus>
30	                    </div>
31	                    <div class="form-group">
32	                        <label class="form-label" for="customerToken">Customer Token</label>
33	                        <input type="text" class="form-input" id="customerToken" name="customerToken"
34	                               placeholder="Token from your delivery receipt" required>
35	                    </div>
36	                    <button type="submit" class="fluent-btn fluent-btn-primary w-full" id="lookup-btn"
37	                            style="min-height:40px; margin-top: var(--fluent-spacing-s);">
38	                        Look Up Delivery
39	                    </button>
40	                </form>
41	            </div>
42	
43	            <!-- Step 2: Rating / Appeal form (shown after successful lookup) -->
44	            <div id="step-action" class="hidden">
45	                <div style="margin-bottom:16px;">
46	                    <strong>Delivery:</strong> <span id="info-tracking"></span><br>
47	                    <strong>Receiver:</strong> <span id="info-receiver"></span><br>
48	                    <strong>Status:</strong> <span id="info-status"></span>
49	                </div>
50	
51	                <div id="rating-section">
52	                    <h3 style="margin-bottom:8px;">Rate this Delivery</h3>
53	                    <form id="rating-form">
54	                        <div class="form-group">
55	                            <label class="form-label">Timeliness (1-5)</label>
56	                            <input type="number" class="form-input" id="timeliness" min="1" max="5" required>
57	                        </div>
58	                        <div class="form-group">
59	                            <label class="form-label">Attitude (1-5)</label>
60	                            <input type="number" class="form-input" id="attitude" min="1" max="5" required>
61	                        </div>
62	                        <div class="form-group">
63	                            <label class="form-label">Accuracy (1-5)</label>
64	                            <input type="number" class="form-input" id="accuracy" min="1" max="5" required>
65	                        </div>
66	                        <div class="form-group">
67	                            <label class="form-label">Comment (optional)</label>
68	                            <textarea class="form-input" id="comment" rows="3"></textarea>
69	                        </div>
70	                        <button type="submit" class="fluent-btn fluent-btn-primary w-full" id="rate-btn"
71	                                style="min-height:40px;">Submit Rating</button>
72	                    </form>
73	                </div>
74	
75	                <div id="appeal-section" class="hidden" style="margin-top:16px; border-top:1px solid var(--fluent-color-neutral-stroke1); padding-top:16px;">
76	                    <h3 style="margin-bottom:8px;">File an Appeal</h3>
77	                    <p class="text-secondary" style="margin-bottom:12px; font-size:0.9em;">
78	                        Appeals must be filed within 48 hours of the rating or violation.
79	                    </p>
80	                    <form id="appeal-form">
81	                        <div class="form-group">
82	                            <label class="form-label" for="appeal-rating">Rating to Appeal</label>
83	                            <select class="form-input" id="appeal-rating" required>
84	                                <option value="">Select a rating...</option>
85	                            </select>
86	                        </div>
87	                        <div class="form-group">
88	                            <label class="form-label" for="appeal-reason">Reason for Appeal</label>
89	                            <textarea class="form-input" id="appeal-reason" rows="3"
90	                                      placeholder="Describe why you are appealing this delivery rating..." required></textarea>
91	                        </div>
92	                        <button type="submit" class="fluent-btn fluent-btn-primary w-full" id="appeal-btn"
93	                                style="min-height:40px;">Submit Appeal</button>
94	                    </form>
95	                </div>
96	
97	                <div style="margin-top:16px;">
98	                    <button class="fluent-btn fluent-btn-secondary w-full" id="back-btn"
99	                            style="min-height:36px;">Back to Lookup</button>
100	                </div>
101	            </div>
102	        </div>
103	    </div>
104	
105	    <div class="toast-container" id="toast-container"></div>
106	
107	    <script src="/static/js/vendor/jquery-3.7.1.min.js"></script>
108	    <script src="/static/js/common/util.js"></script>
109	    <script src="/static/js/common/toast.js"></script>
110	    <script>
111	    $(function() {
112	        var currentTracking, currentToken, currentReceiver;
113	
114	        $('#lookup-form').on('submit', function(e) {
115	            e.preventDefault();
116	            $('#portal-error').addClass('hidden');
117	            currentTracking = $('#trackingNumber').val().trim();
118	            currentToken = $('#customerToken').val().trim();
119	
120	            $('#lookup-btn').prop('disabled', true).text('Looking up...');
121	
122	            $.ajax({
123	                url: '/api/credibility/customer/lookup',
124	                method: 'GET',
125	                data: { trackingNumber: currentTracking, customerToken: currentToken }
126	            }).done(function(resp) {
127	                if (resp.code === 200 && resp.data) {
128	                    currentReceiver = resp.data.receiverName;
129	                    $('#info-tracking').text(resp.data.trackingNumber);
130	                    $('#info-receiver').text(resp.data.receiverName);
131	                    $('#info-status').text(resp.data.status);
132	                    $('#step-lookup').addClass('hidden');
133	                    $('#step-action').removeClass('hidden');
134	                    if (!resp.data.canRate) {
135	                        $('#rating-section').html('<p class="text-secondary">This delivery is not yet eligible for rating.</p>');
136	                    }
137	                    if (resp.data.canAppeal && resp.data.appealableRatings && resp.data.appealableRatings.length > 0) {
138	                        var $sel = $('#appeal-rating').empty().append('<option value="">Select a rating...</option>');
139	                        $.each(resp.data.appealableRatings, function(i, r) {
140	                            var label = 'Rating #' + r.id + ' — T:' + r.timeliness + ' A:' + r.attitude + ' Ac:' + r.accuracy + ' (' + r.createdAt + ')';
141	                            $sel.append($('<option>').val(r.id).text(label));
142	                        });
143	                        $('#appeal-section').removeClass('hidden');
144	                    } else {
145	                        $('#appeal-section').addClass('hidden');
146	                    }
147	                } else {
148	                    $('#portal-error').text(resp.message || 'Lookup failed.').removeClass('hidden');
149	                }
150	                $('#lookup-btn').prop('disabled', false).text('Look Up Delivery');
151	            }).fail(function(xhr) {
152	                var msg = xhr.responseJSON && xhr.responseJSON.message ? xhr.responseJSON.message : 'Unable to find delivery.';
153	                $('#portal-error').text(msg).removeClass('hidden');
154	                $('#lookup-btn').prop('disabled', false).text('Look Up Delivery');
155	            });
156	        });
157	
158	        $('#rating-form').on('submit', function(e) {
159	            e.preventDefault();
160	            $('#portal-error').addClass('hidden');
161	            $('#rate-btn').prop('disabled', true).text('Submitting...');
162	
163	            $.ajax({
164	                url: '/api/credibility/ratings/customer',
165	                method: 'POST',
166	                contentType: 'application/json',
167	                data: JSON.stringify({
168	                    trackingNumber: currentTracking,
169	                    receiverName: currentReceiver,
170	                    customerToken: currentToken,
171	                    timeliness: parseInt($('#timeliness').val()),
172	                    attitude: parseInt($('#attitude').val()),
173	                    accuracy: parseInt($('#accuracy').val()),
174	                    comment: $('#comment').val()
175	                })
176	            }).done(function(resp) {
177	                if (resp.code === 200 || resp.code === 201) {
178	                    $('#portal-success').text('Thank you! Your rating has been submitted.').removeClass('hidden');
179	                    $('#rating-section').addClass('hidden');
180	                } else {
181	                    $('#portal-error').text(resp.message || 'Rating submission failed.').removeClass('hidden');
182	                }
183	                $('#rate-btn').prop('disabled', false).text('Submit Rating');
184	            }).fail(function(xhr) {
185	                var msg = xhr.responseJSON && xhr.responseJSON.message ? xhr.responseJSON.message : 'Rating submission failed.';
186	                $('#portal-error').text(msg).removeClass('hidden');
187	                $('#rate-btn').prop('disabled', false).text('Submit Rating');
188	            });
189	        });
190	
191	        $('#appeal-form').on('submit', function(e) {
192	            e.preventDefault();
193	            $('#portal-error').addClass('hidden');
194	            $('#appeal-btn').prop('disabled', true).text('Submitting...');
195	
196	            $.ajax({
197	                url: '/api/credibility/appeals/customer',
198	                method: 'POST',
199	                contentType: 'application/json',
200	                data: JSON.stringify({
201	                    trackingNumber: currentTracking,
202	                    receiverName: currentReceiver,
203	                    customerToken: currentToken,
204	                    reason: $('#appeal-reason').val(),
205	                    ratingId: parseInt($('#appeal-rating').val()) || null
206	                })
207	            }).done(function(resp) {
208	                if (resp.code === 200 || resp.code === 201) {
209	                    $('#portal-success').text('Your appeal has been submitted and will be reviewed.').removeClass('hidden');
210	                    $('#appeal-section').addClass('hidden');
211	                } else {
212	                    $('#portal-error').text(resp.message || 'Appeal submission failed.').removeClass('hidden');
213	                }
214	                $('#appeal-btn').prop('disabled', false).text('Submit Appeal');
215	            }).fail(function(xhr) {
216	                var msg = xhr.responseJSON && xhr.responseJSON.message ? xhr.responseJSON.message : 'Appeal submission failed.';
217	                $('#portal-error').text(msg).removeClass('hidden');
218	                $('#appeal-btn').prop('disabled', false).text('Submit Appeal');
219	            });
220	        });
221	
222	        $('#back-btn').on('click', function() {
223	            $('#step-action').addClass('hidden');
224	            $('#step-lookup').removeClass('hidden');
225	            $('#portal-error').addClass('hidden');
226	            $('#portal-success').addClass('hidden');
227	            $('#appeal-section').addClass('hidden');
228	            $('#appeal-reason').val('');
229	        });
230	    });
231	    </script>
232	</body>
233	</html>
234
